import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface Product {
  id: string;
  name: string;
  description: string;
  quantity: number;
  price: number;
  arrivalDate: string;
  imageUrl: string;
}

export interface Sale {
  id: string;
  productId: string;
  productName: string;
  quantity: number;
  totalPrice: number;
  date: string;
}

export enum View {
  SHOP = 'SHOP',
  ADMIN_INVENTORY = 'ADMIN_INVENTORY',
  ADMIN_STATS = 'ADMIN_STATS'
}

import { GoogleGenAI } from "@google/genai";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const generateProductDescription = async (productName: string): Promise<string> => {
  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: `Génère une description luxueuse et vendeuse en français pour un produit cosmétique nommé "${productName}". La description doit être courte, élégante et mettre en avant la qualité.`,
      config: {
        temperature: 0.7,
        maxOutputTokens: 200,
      }
    });
    return response.text?.trim() || "Description non disponible.";
  } catch (error) {
    console.error("Gemini Error:", error);
    return "Erreur lors de la génération de la description.";
  }
};

import React, { useState, useEffect } from 'react';
import { View, Product, Sale } from './types';
import Navbar from './components/Navbar';
import Shop from './components/Shop';
import InventoryManager from './components/InventoryManager';
import StatsDashboard from './components/StatsDashboard';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.SHOP);
  const [products, setProducts] = useState<Product[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);

  // Load initial data
  useEffect(() => {
    const savedProducts = localStorage.getItem('ibra_products');
    const savedSales = localStorage.getItem('ibra_sales');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedSales) setSales(JSON.parse(savedSales));
  }, []);

  // Save data whenever it changes
  useEffect(() => {
    localStorage.setItem('ibra_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('ibra_sales', JSON.stringify(sales));
  }, [sales]);

  const addProduct = (product: Product) => {
    setProducts(prev => [...prev, product]);
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const recordSale = (productId: string, quantitySold: number) => {
    const product = products.find(p => p.id === productId);
    if (!product || product.quantity < quantitySold) return;

    // Update stock
    setProducts(prev => prev.map(p => 
      p.id === productId ? { ...p, quantity: p.quantity - quantitySold } : p
    ));

    // Record sale
    const newSale: Sale = {
      id: Date.now().toString(),
      productId,
      productName: product.name,
      quantity: quantitySold,
      totalPrice: product.price * quantitySold,
      date: new Date().toISOString()
    };
    setSales(prev => [...prev, newSale]);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar currentView={currentView} setView={setCurrentView} />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {currentView === View.SHOP && (
          <Shop products={products} onOrder={recordSale} />
        )}

        {currentView === View.ADMIN_INVENTORY && (
          <InventoryManager 
            products={products} 
            onAdd={addProduct} 
            onDelete={deleteProduct} 
          />
        )}

        {currentView === View.ADMIN_STATS && (
          <StatsDashboard products={products} sales={sales} />
        )}
      </main>

      <footer className="bg-stone-900 text-stone-400 py-10 mt-12 border-t border-stone-800">
        <div className="container mx-auto px-4 text-center">
          <h2 className="brand-font text-2xl text-white mb-4">IbraCosm</h2>
          <p className="mb-6">L'élégance à portée de main au Mali.</p>
          <div className="flex justify-center space-x-6 text-sm">
            <a href="#" className="hover:text-white transition-colors">Instagram</a>
            <a href="#" className="hover:text-white transition-colors">Facebook</a>
            <a href="https://wa.me/22396406129" className="hover:text-white transition-colors">WhatsApp</a>
          </div>
          <p className="mt-8 text-xs">&copy; 2024 IbraCosm. Tous droits réservés.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

