    const text = `Bonjour IbraCosm, je souhaite commander : ${product.name}. Prix: ${product.price} FCFA. Est-il disponible ?`;
    const url = `https://wa.me/22396406129?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');
    onOrder(product.id, 1); // Record as a local sale for tracking
  };

  return (
    <div>
      <section className="mb-12 text-center">
        <h2 className="text-4xl font-bold text-stone-900 mb-4">Notre Collection</h2>
        <p className="text-stone-500 max-w-2xl mx-auto">
          Découvrez notre sélection exclusive de produits cosmétiques pour sublimer votre beauté naturelle.
        </p>
      </section>

      {products.length === 0 ? (
        <div className="text-center py-20 bg-stone-50 rounded-2xl border-2 border-dashed border-stone-200">
          <p className="text-stone-400">Aucun produit en stock pour le moment. Revenez bientôt !</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
          {products.map(product => (
            <div 
              key={product.id} 
              className="bg-white rounded-xl overflow-hidden shadow-sm border border-stone-100 hover:shadow-xl transition-shadow group flex flex-col"
            >
              <div className="relative h-64 overflow-hidden">
                <img 
                  src={product.imageUrl || 'https://picsum.photos/400/400?grayscale'} 
                  alt={product.name}
                  className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-500"
                />
                {product.quantity === 0 && (
                  <div className="absolute inset-0 bg-stone-900/60 flex items-center justify-center">
                    <span className="text-white font-bold px-4 py-2 border-2 border-white uppercase tracking-widest">Rupture de Stock</span>
                  </div>
