export interface Product {
  id: string;
  name: string;
  description: string;
  quantity: number;
  price: number;
  arrivalDate: string;
  imageUrl: string;
}

export interface Sale {
  id: string;
  productId: string;
  productName: string;
  quantity: number;
  totalPrice: number;
  date: string;
}

export interface CartItem {
  product: Product;
  quantity: number;
}

export enum View {
  SHOP = 'SHOP',
  ADMIN_INVENTORY = 'ADMIN_INVENTORY',
  ADMIN_STATS = 'ADMIN_STATS'
}

import React, { useState, useEffect } from 'react';
import { View, Product, Sale, CartItem } from './types';
import Navbar from './components/Navbar';
import Shop from './components/Shop';
import InventoryManager from './components/InventoryManager';
import StatsDashboard from './components/StatsDashboard';
import CartModal from './components/CartModal';
import AdminLoginModal from './components/AdminLoginModal';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<View>(View.SHOP);
  const [products, setProducts] = useState<Product[]>([]);
  const [sales, setSales] = useState<Sale[]>([]);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [isAdmin, setIsAdmin] = useState<boolean>(false);
  const [isCartOpen, setIsCartOpen] = useState<boolean>(false);
  const [isLoginOpen, setIsLoginOpen] = useState<boolean>(false);

  // Load initial data
  useEffect(() => {
    const savedProducts = localStorage.getItem('ibra_products');
    const savedSales = localStorage.getItem('ibra_sales');
    const savedAdmin = localStorage.sessionStorage.getItem('ibra_admin');

    if (savedProducts) setProducts(JSON.parse(savedProducts));
    if (savedSales) setSales(JSON.parse(savedSales));
    if (savedAdmin === 'true') setIsAdmin(true);
  }, []);

  // Save data whenever it changes
  useEffect(() => {
    localStorage.setItem('ibra_products', JSON.stringify(products));
  }, [products]);

  useEffect(() => {
    localStorage.setItem('ibra_sales', JSON.stringify(sales));
  }, [sales]);

  const addProduct = (product: Product) => {
    setProducts(prev => [...prev, product]);
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const addToCart = (product: Product) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        if (existing.quantity >= product.quantity) return prev;
        return prev.map(item => 
          item.product.id === product.id ? { ...item, quantity: item.quantity + 1 } : item
        );
      }
      return [...prev, { product, quantity: 1 }];
    });
    setIsCartOpen(true);
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.product.id !== productId));
  };

  const updateCartQuantity = (productId: string, delta: number) => {
    setCart(prev => prev.map(item => {
      if (item.product.id === productId) {
        const newQty = Math.max(1, Math.min(item.product.quantity, item.quantity + delta));
        return { ...item, quantity: newQty };
      }
      return item;
    }));
  };

  const handleCheckout = () => {
    // Record sales locally
    cart.forEach(item => {
      const product = products.find(p => p.id === item.product.id);
      if (!product) return;

      // Update stock
      setProducts(prev => prev.map(p => 
        p.id === item.product.id ? { ...p, quantity: p.quantity - item.quantity } : p
      ));

      // Record sale
      const newSale: Sale = {
        id: Date.now().toString() + Math.random(),
        productId: item.product.id,
        productName: item.product.name,
        quantity: item.quantity,
        totalPrice: item.product.price * item.quantity,
        date: new Date().toISOString()
      };
      setSales(prev => [...prev, newSale]);
    });

    // Generate WhatsApp Message
    const itemsList = cart.map(item => `- ${item.product.name} (x${item.quantity}) : ${(item.product.price * item.quantity).toLocaleString()} FCFA`).join('\n');
    const total = cart.reduce((sum, item) => sum + (item.product.price * item.quantity), 0);
    const text = `Bonjour IbraCosm, je souhaite passer la commande suivante :\n\n${itemsList}\n\nTotal : ${total.toLocaleString()} FCFA\n\nMerci de me confirmer la disponibilité !`;

    const url = `https://wa.me/22396406129?text=${encodeURIComponent(text)}`;
    window.open(url, '_blank');

    setCart([]);
    setIsCartOpen(false);
  };

  const handleAdminLogin = (password: string) => {
    if (password === 'ibra2024') { // Simple password for demo
      setIsAdmin(true);
      sessionStorage.setItem('ibra_admin', 'true');
      setIsLoginOpen(false);
      return true;
    }
    return false;
  };

  const handleLogout = () => {
    setIsAdmin(false);
    sessionStorage.removeItem('ibra_admin');
    setCurrentView(View.SHOP);
  };

  return (
    <div className="min-h-screen flex flex-col">
      <Navbar 
        currentView={currentView} 
        setView={setCurrentView} 
        isAdmin={isAdmin} 
        onLoginClick={() => setIsLoginOpen(true)}
        onLogout={handleLogout}
        cartCount={cart.reduce((sum, item) => sum + item.quantity, 0)}
        onCartClick={() => setIsCartOpen(true)}
      />

      <main className="flex-grow container mx-auto px-4 py-8 max-w-7xl">
        {currentView === View.SHOP && (
          <Shop products={products} onAddToCart={addToCart} />
        )}

        {isAdmin && currentView === View.ADMIN_INVENTORY && (
          <InventoryManager 
            products={products} 
            onAdd={addProduct} 
            onDelete={deleteProduct} 
          />
        )}

        {isAdmin && currentView === View.ADMIN_STATS && (
          <StatsDashboard products={products} sales={sales} />
        )}

        {!isAdmin && currentView !== View.SHOP && (
          <div className="text-center py-20">
            <h2 className="text-2xl font-bold text-stone-800">Accès Restreint</h2>
            <p className="text-stone-500 mt-2">Veuillez vous connecter en tant qu'administrateur pour voir cette page.</p>
            <button 
              onClick={() => setCurrentView(View.SHOP)}
              className="mt-6 text-rose-600 font-bold underline"
            >
              Retour à la boutique
            </button>
          </div>
        )}
      </main>

      <CartModal 
        isOpen={isCartOpen} 
        onClose={() => setIsCartOpen(false)} 
        items={cart}
        onRemove={removeFromCart}
        onUpdateQty={updateCartQuantity}
        onCheckout={handleCheckout}
      />

      <AdminLoginModal 
        isOpen={isLoginOpen} 
        onClose={() => setIsLoginOpen(false)} 
        onLogin={handleAdminLogin} 
      />

      <footer className="bg-stone-900 text-stone-400 py-10 mt-12 border-t border-stone-800">
        <div className="container mx-auto px-4 text-center">
          <h2 className="brand-font text-2xl text-white mb-4">IbraCosm</h2>
          <p className="mb-6">L'élégance à portée de main au Mali.</p>
          <div className="flex justify-center space-x-6 text-sm">
            <a href="#" className="hover:text-white transition-colors">Instagram</a>
            <a href="#" className="hover:text-white transition-colors">Facebook</a>
            <a href="https://wa.me/22396406129" className="hover:text-white transition-colors">WhatsApp</a>
          </div>
          <p className="mt-8 text-xs">&copy; 2024 IbraCosm. Tous droits réservés.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;

