            <button 
              onClick={() => setSearchTerm('')}
              className="absolute inset-y-0 right-0 pr-3 flex items-center text-stone-300 hover:text-stone-500"
            >
              ✕
            </button>
          )}
        </div>
      </section>

      {products.length === 0 ? (
        <div className="text-center py-20 bg-stone-50 rounded-2xl border-2 border-dashed border-stone-200">
