              </div>

              <div className="p-5 flex-grow flex flex-col">
                <div className="flex justify-between items-start mb-2">
                  <h3 className="font-bold text-lg text-stone-900">{product.name}</h3>
                  <span className="text-rose-600 font-bold">{product.price.toLocaleString()} FCFA</span>
                </div>
                <p className="text-stone-500 text-sm mb-4 line-clamp-2 flex-grow">
                  {product.description}
