                <div className="flex space-x-2 mt-auto">
                  <button 
                    disabled={product.quantity === 0}
                    onClick={() => onAddToCart(product)}
                    className="flex-grow bg-rose-600 text-white py-2 rounded-lg font-medium hover:bg-rose-700 transition-colors disabled:opacity-50 disabled:cursor-not-allowed"
                  >
                    Ajouter au panier
                  </button>
                  <button 
                    onClick={() => setSelectedProduct(product)}
                    className="bg-stone-100 text-stone-600 p-2 rounded-lg hover:bg-stone-200 transition-colors"
