                    👁️
                  </button>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Detail Modal */}
      {selectedProduct && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-[100] p-4">
          <div className="bg-white rounded-3xl max-w-2xl w-full overflow-hidden flex flex-col md:flex-row relative animate-in fade-in zoom-in duration-300">
            <button 
              onClick={() => setSelectedProduct(null)}
              className="absolute top-4 right-4 bg-white/80 hover:bg-white rounded-full p-2 z-10 shadow-md transition-colors"
            >
              ✕
            </button>
            <div className="md:w-1/2 h-64 md:h-auto">
              <img 
                src={selectedProduct.imageUrl || 'https://picsum.photos/400/400'} 
                className="w-full h-full object-cover"
                alt={selectedProduct.name}
              />
            </div>
            <div className="md:w-1/2 p-8">
              <h2 className="text-3xl font-bold mb-2 brand-font">{selectedProduct.name}</h2>
