              <div className="space-y-4 mb-6">
                <p className="text-stone-600 leading-relaxed text-sm">{selectedProduct.description}</p>
                <div className="text-xs text-stone-400">
                  <p>Quantité disponible: <span className="font-medium text-stone-700">{selectedProduct.quantity}</span></p>
                </div>
              </div>
              <button 
                disabled={selectedProduct.quantity === 0}
                onClick={() => {
                  onAddToCart(selectedProduct);
                  setSelectedProduct(null);
                }}
                className="w-full bg-rose-600 text-white py-4 rounded-xl font-bold hover:bg-rose-700 transition-all disabled:opacity-50 shadow-lg shadow-rose-100"
              >
                Ajouter au panier
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

