                  onClick={() => handleQtyChange(-1)}
                  className="w-8 h-8 rounded-full bg-white border border-stone-200 flex items-center justify-center text-stone-600 hover:bg-stone-100 transition-colors shadow-sm"
                >
                  -
                </button>
                <span className="font-bold text-stone-900 w-4 text-center">{qty}</span>
                <button 
                  onClick={() => handleQtyChange(1)}
                  className="w-8 h-8 rounded-full bg-white border border-stone-200 flex items-center justify-center text-stone-600 hover:bg-stone-100 transition-colors shadow-sm"
                >
                  +
                </button>
              </div>
            </div>
          )}

          <div className="flex space-x-2">
            <button 
              disabled={product.quantity === 0}
              onClick={() => {
                onAddToCart(product, qty);
                setQty(1); // Reset local quantity after add
              }}
              className="flex-grow bg-rose-600 text-white py-3 rounded-xl font-bold hover:bg-rose-700 transition-all disabled:opacity-50 disabled:cursor-not-allowed shadow-md shadow-rose-100"
            >
              Ajouter au panier
            </button>
            <button 
              onClick={() => onViewDetails(product)}
              className="bg-stone-100 text-stone-600 p-3 rounded-xl hover:bg-stone-200 transition-colors"
              title="Voir détails"
            >
              👁️
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

